searchData={"items":[{"type":"module","title":"Hibana.Plugins.LiveView","doc":"LiveView channel plugin for real-time WebSocket connections.","ref":"Hibana.Plugins.LiveView.html"},{"type":"module","title":"Features - Hibana.Plugins.LiveView","doc":"- WebSocket upgrade handling for LiveView\n- Phoenix-style LiveView socket management\n- Event handling from client\n- Server-rendered HTML updates","ref":"Hibana.Plugins.LiveView.html#module-features"},{"type":"module","title":"Usage - Hibana.Plugins.LiveView","doc":"plug Hibana.Plugins.LiveView, handler: MyApp.CounterLive","ref":"Hibana.Plugins.LiveView.html#module-usage"},{"type":"module","title":"Routes - Hibana.Plugins.LiveView","doc":"Access LiveView at:\n\n    GET /lv/socket/*path","ref":"Hibana.Plugins.LiveView.html#module-routes"},{"type":"module","title":"LiveView Handler - Hibana.Plugins.LiveView","doc":"Create a handler module:\n\n    defmodule MyApp.CounterLive do\n      use Hibana.LiveView\n\n      def mount(_params, _session, socket) do\n        {:ok, assign(socket, count: 0)}\n      end\n\n      def render(assigns) do\n        \" Count: #{assigns[:count]} \"\n      end\n\n      def handle_event(\"increment\", _params, socket) do\n        {:noreply, assign(socket, count: socket.assigns.count + 1)}\n      end\n    end","ref":"Hibana.Plugins.LiveView.html#module-liveview-handler"},{"type":"module","title":"WebSocket Connection - Hibana.Plugins.LiveView","doc":"Client connects to:\n\n    ws://localhost:4000/lv/socket/counter\n\nSend events as JSON:\n\n    ws.send(JSON.stringify({event: \"increment\", value: 1}))","ref":"Hibana.Plugins.LiveView.html#module-websocket-connection"},{"type":"module","title":"Module Functions - Hibana.Plugins.LiveView","doc":"","ref":"Hibana.Plugins.LiveView.html#module-module-functions"},{"type":"module","title":"build_socket/3 - Hibana.Plugins.LiveView","doc":"Build a LiveView socket:\n\n    socket = Hibana.Plugins.LiveView.build_socket(handler, endpoint, id)","ref":"Hibana.Plugins.LiveView.html#module-build_socket-3"},{"type":"module","title":"handle_event/4 - Hibana.Plugins.LiveView","doc":"Handle incoming events:\n\n    new_socket = LiveView.handle_event(socket, \"click\", %{}, handler)","ref":"Hibana.Plugins.LiveView.html#module-handle_event-4"},{"type":"module","title":"render/2 - Hibana.Plugins.LiveView","doc":"Render the LiveView template:\n\n    html = LiveView.render(socket, handler)","ref":"Hibana.Plugins.LiveView.html#module-render-2"},{"type":"module","title":"Options - Hibana.Plugins.LiveView","doc":"- `:handler` - The LiveView handler module that implements `mount/3`, `render/1`, and `handle_event/3` callbacks (required)","ref":"Hibana.Plugins.LiveView.html#module-options"},{"type":"function","title":"Hibana.Plugins.LiveView.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.LiveView.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.LiveView.build_socket/3","doc":"","ref":"Hibana.Plugins.LiveView.html#build_socket/3"},{"type":"function","title":"Hibana.Plugins.LiveView.handle_event/4","doc":"","ref":"Hibana.Plugins.LiveView.html#handle_event/4"},{"type":"function","title":"Hibana.Plugins.LiveView.render/2","doc":"","ref":"Hibana.Plugins.LiveView.html#render/2"},{"type":"function","title":"Hibana.Plugins.LiveView.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.LiveView.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.RateLimiter.State","doc":"","ref":"Hibana.Plugins.RateLimiter.State.html"},{"type":"function","title":"Hibana.Plugins.RateLimiter.State.new/3","doc":"","ref":"Hibana.Plugins.RateLimiter.State.html#new/3"},{"type":"module","title":"Hibana.Plugins.APIKey","doc":"API key authentication plugin. Supports header, query param, or bearer token.","ref":"Hibana.Plugins.APIKey.html"},{"type":"module","title":"Usage - Hibana.Plugins.APIKey","doc":"plug Hibana.Plugins.APIKey,\n      keys: [\"sk_live_abc123\", \"sk_live_def456\"],\n      header: \"x-api-key\"\n\n    # Or with a validator function\n    plug Hibana.Plugins.APIKey,\n      validator: &MyApp.Auth.validate_api_key/1,\n      sources: [:header, :query]","ref":"Hibana.Plugins.APIKey.html#module-usage"},{"type":"module","title":"Options - Hibana.Plugins.APIKey","doc":"- `:keys` - List of valid API key strings for static validation (default: `[]`)\n- `:validator` - A function `(String.t() -> boolean())` for custom key validation; takes precedence over `:keys` (default: `nil`)\n- `:header` - Request header name to extract the API key from (default: `\"x-api-key\"`)\n- `:query_param` - Query parameter name to extract the API key from (default: `\"api_key\"`)\n- `:sources` - List of sources to check for the API key, in order; valid values are `:header`, `:query`, and `:bearer` (default: `[:header, :query, :bearer]`)","ref":"Hibana.Plugins.APIKey.html#module-options"},{"type":"function","title":"Hibana.Plugins.APIKey.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.APIKey.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.APIKey.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.APIKey.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.Auth","doc":"HTTP Basic authentication plugin.","ref":"Hibana.Plugins.Auth.html"},{"type":"module","title":"Features - Hibana.Plugins.Auth","doc":"- RFC 7617 compliant Basic Auth\n- Customizable realm name\n- Pluggable validator function\n- Automatic 401 response with WWW-Authenticate header","ref":"Hibana.Plugins.Auth.html#module-features"},{"type":"module","title":"Usage - Hibana.Plugins.Auth","doc":"# Basic usage with default realm\n    plug Hibana.Plugins.Auth\n\n    # With custom realm\n    plug Hibana.Plugins.Auth, realm: \"Admin Area\"\n\n    # With custom validator\n    plug Hibana.Plugins.Auth,\n      validator: fn username, password ->\n        username == \"admin\" && password == \"secret\"\n      end","ref":"Hibana.Plugins.Auth.html#module-usage"},{"type":"module","title":"Options - Hibana.Plugins.Auth","doc":"- `:realm` - Authentication realm name (default: `\"Restricted\"`)\n- `:validator` - Custom validation function (default: always returns `false`)","ref":"Hibana.Plugins.Auth.html#module-options"},{"type":"module","title":"Validator Function - Hibana.Plugins.Auth","doc":"The validator receives username and password:\n\n    validator = fn username, password ->\n      # Check against database, LDAP, etc.\n      username == \"admin\" && password == \"secret\"\n    end","ref":"Hibana.Plugins.Auth.html#module-validator-function"},{"type":"module","title":"Conn Assignments - Hibana.Plugins.Auth","doc":"On successful authentication:\n\n    conn.assigns.current_user  # => \"username\"","ref":"Hibana.Plugins.Auth.html#module-conn-assignments"},{"type":"module","title":"Response - Hibana.Plugins.Auth","doc":"On failed authentication:\n\n    HTTP 401 Unauthorized\n    WWW-Authenticate: Basic realm=\"Protected Area\"","ref":"Hibana.Plugins.Auth.html#module-response"},{"type":"function","title":"Hibana.Plugins.Auth.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.Auth.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.Auth.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.Auth.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.CORS","doc":"CORS (Cross-Origin Resource Sharing) plugin for Hibana.","ref":"Hibana.Plugins.CORS.html"},{"type":"module","title":"Features - Hibana.Plugins.CORS","doc":"- Configurable allowed origins (including regex patterns)\n- Automatic OPTIONS handling for preflight requests\n- Support for credentials and max-age headers\n- Configurable allowed methods and headers","ref":"Hibana.Plugins.CORS.html#module-features"},{"type":"module","title":"Usage - Hibana.Plugins.CORS","doc":"# Basic usage (allow all origins)\n    plug Hibana.Plugins.CORS\n\n    # With custom configuration\n    plug Hibana.Plugins.CORS,\n      origins: [\"https://example.com\", \"https://app.example.com\"],\n      headers: [\"Content-Type\", \"Authorization\", \"X-Custom-Header\"],\n      credentials: true,\n      max_age: 86400\n\n    # With regex pattern for origins\n    plug Hibana.Plugins.CORS,\n      origins: [\"^https://.*\\.example\\.com$\"]","ref":"Hibana.Plugins.CORS.html#module-usage"},{"type":"module","title":"Options - Hibana.Plugins.CORS","doc":"- `:origins` - List of allowed origins (default: `[\"*\"]`)\n- `:methods` - Allowed HTTP methods (default: standard methods)\n- `:headers` - Allowed request headers (default: `[\"Content-Type\", \"Authorization\"]`)\n- `:credentials` - Allow credentials (default: `true`)\n- `:max_age` - Preflight cache duration in seconds (default: `86400`)","ref":"Hibana.Plugins.CORS.html#module-options"},{"type":"module","title":"Response Headers - Hibana.Plugins.CORS","doc":"- `access-control-allow-origin` - The allowed origin\n- `access-control-allow-methods` - Comma-separated allowed methods\n- `access-control-allow-headers` - Comma-separated allowed headers\n- `access-control-allow-credentials` - \"true\" if credentials allowed\n- `access-control-max-age` - Preflight cache duration","ref":"Hibana.Plugins.CORS.html#module-response-headers"},{"type":"function","title":"Hibana.Plugins.CORS.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.CORS.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.CORS.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.CORS.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.DistributedRateLimiter","doc":"Distributed rate limiter that works across cluster nodes.\nUses the Cluster module for cross-node counter synchronization.","ref":"Hibana.Plugins.DistributedRateLimiter.html"},{"type":"module","title":"Usage - Hibana.Plugins.DistributedRateLimiter","doc":"plug Hibana.Plugins.DistributedRateLimiter,\n      max_requests: 1000,\n      window_ms: 60_000,\n      sync_interval: 5_000","ref":"Hibana.Plugins.DistributedRateLimiter.html#module-usage"},{"type":"module","title":"Options - Hibana.Plugins.DistributedRateLimiter","doc":"- `:max_requests` - Maximum number of requests allowed within the time window (default: `1000`)\n- `:window_ms` - Time window in milliseconds for rate limiting (default: `60_000`)\n- `:key_fn` - A function `(Plug.Conn.t() -> String.t())` that returns a rate-limiting key for the request; defaults to client IP address","ref":"Hibana.Plugins.DistributedRateLimiter.html#module-options"},{"type":"function","title":"Hibana.Plugins.DistributedRateLimiter.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.DistributedRateLimiter.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.DistributedRateLimiter.local_count_for/2","doc":"","ref":"Hibana.Plugins.DistributedRateLimiter.html#local_count_for/2"},{"type":"function","title":"Hibana.Plugins.DistributedRateLimiter.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.DistributedRateLimiter.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.JWT","doc":"JWT (JSON Web Token) authentication plugin.","ref":"Hibana.Plugins.JWT.html"},{"type":"module","title":"Features - Hibana.Plugins.JWT","doc":"- Token verification with configurable algorithms\n- Automatic token expiration checking\n- Claims extraction and assignment to conn\n- Token generation utilities","ref":"Hibana.Plugins.JWT.html#module-features"},{"type":"module","title":"Usage - Hibana.Plugins.JWT","doc":"# Basic usage\n    plug Hibana.Plugins.JWT, secret: \"my_secret_key\"\n\n    # With custom options\n    plug Hibana.Plugins.JWT,\n      secret: \"my_secret_key\",\n      algorithm: :HS256,\n      header_name: \"authorization\",\n      scheme: \"Bearer\"","ref":"Hibana.Plugins.JWT.html#module-usage"},{"type":"module","title":"Options - Hibana.Plugins.JWT","doc":"- `:secret` - Secret key for token verification (required)\n- `:algorithm` - JWT algorithm (`:HS256`, `:HS384`, `:HS512`) (default: `:HS256`)\n- `:claims` - Expected claims configuration (default: includes exp/iat)\n- `:header_name` - Header to extract token from (default: `\"authorization\"`)\n- `:scheme` - Auth scheme (default: `\"Bearer\"`)","ref":"Hibana.Plugins.JWT.html#module-options"},{"type":"module","title":"Conn Assignments - Hibana.Plugins.JWT","doc":"After successful verification, these assignments are made:\n\n- `conn.assigns.jwt_claims` - Full JWT claims map\n- `conn.assigns.current_user` - Value of \"sub\" claim","ref":"Hibana.Plugins.JWT.html#module-conn-assignments"},{"type":"module","title":"Module Functions - Hibana.Plugins.JWT","doc":"","ref":"Hibana.Plugins.JWT.html#module-module-functions"},{"type":"module","title":"sign/2-3 - Hibana.Plugins.JWT","doc":"Generate a new JWT token:\n\n    claims = %{\"sub\" => \"user123\", \"name\" => \"John\"}\n    token = Hibana.Plugins.JWT.sign(claims, \"secret\", exp: 3600)","ref":"Hibana.Plugins.JWT.html#module-sign-2-3"},{"type":"module","title":"verify/2-3 - Hibana.Plugins.JWT","doc":"Verify and decode a token:\n\n    {:ok, claims} = Hibana.Plugins.JWT.verify(token, \"secret\")","ref":"Hibana.Plugins.JWT.html#module-verify-2-3"},{"type":"module","title":"decode/1 - Hibana.Plugins.JWT","doc":"Decode without verification (for debugging):\n\n    {:ok, claims} = Hibana.Plugins.JWT.decode(token)","ref":"Hibana.Plugins.JWT.html#module-decode-1"},{"type":"function","title":"Hibana.Plugins.JWT.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.JWT.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.JWT.decode/1","doc":"Extract claims from a token without verification (for debugging).","ref":"Hibana.Plugins.JWT.html#decode/1"},{"type":"function","title":"Hibana.Plugins.JWT.sign/3","doc":"Generate a new JWT token.","ref":"Hibana.Plugins.JWT.html#sign/3"},{"type":"function","title":"Hibana.Plugins.JWT.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.JWT.html#start_link/1"},{"type":"function","title":"Hibana.Plugins.JWT.verify/3","doc":"Verify and decode a JWT token.","ref":"Hibana.Plugins.JWT.html#verify/3"},{"type":"module","title":"Hibana.Plugins.OAuth","doc":"OAuth 2.0 authorization plugin supporting multiple providers.","ref":"Hibana.Plugins.OAuth.html"},{"type":"module","title":"Supported Providers - Hibana.Plugins.OAuth","doc":"- Google OAuth 2.0\n- GitHub OAuth\n- Facebook OAuth","ref":"Hibana.Plugins.OAuth.html#module-supported-providers"},{"type":"module","title":"Usage - Hibana.Plugins.OAuth","doc":"# Google OAuth\n    plug Hibana.Plugins.OAuth,\n      provider: :google,\n      client_id: \"your_client_id\",\n      client_secret: \"your_client_secret\",\n      redirect_uri: \"http://localhost:4000/auth/callback\"\n\n    # GitHub OAuth\n    plug Hibana.Plugins.OAuth,\n      provider: :github,\n      client_id: \"your_client_id\",\n      client_secret: \"your_client_secret\",\n      redirect_uri: \"http://localhost:4000/auth/callback\"","ref":"Hibana.Plugins.OAuth.html#module-usage"},{"type":"module","title":"Routes - Hibana.Plugins.OAuth","doc":"The plugin handles these routes automatically:\n\n- `GET /auth/login` - Initiates OAuth flow\n- `GET /auth/callback` - Handles OAuth callback","ref":"Hibana.Plugins.OAuth.html#module-routes"},{"type":"module","title":"Flow - Hibana.Plugins.OAuth","doc":"1. User visits `/auth/login`\n2. Redirected to provider's authorization page\n3. User grants permission\n4. Redirect back to `/auth/callback`\n5. Plugin exchanges code for token\n6. Fetches user info from provider\n7. Generates JWT and sets cookie\n8. Redirects to `/`","ref":"Hibana.Plugins.OAuth.html#module-flow"},{"type":"module","title":"Options - Hibana.Plugins.OAuth","doc":"- `:provider` - OAuth provider (`:google`, `:github`, `:facebook`)\n- `:client_id` - OAuth client ID\n- `:client_secret` - OAuth client secret\n- `:redirect_uri` - Callback URL\n- `:scope` - OAuth scope (optional, uses provider defaults)\n- `:jwt_secret` - Secret for generated JWT (required)","ref":"Hibana.Plugins.OAuth.html#module-options"},{"type":"module","title":"Module Functions - Hibana.Plugins.OAuth","doc":"","ref":"Hibana.Plugins.OAuth.html#module-module-functions"},{"type":"module","title":"authorization_url/2 - Hibana.Plugins.OAuth","doc":"Generate authorization URL:\n\n    url = Hibana.Plugins.OAuth.authorization_url(:google, client_id: \"...\", redirect_uri: \"...\")","ref":"Hibana.Plugins.OAuth.html#module-authorization_url-2"},{"type":"module","title":"exchange_token/2 - Hibana.Plugins.OAuth","doc":"Exchange authorization code for access token:\n\n    {:ok, token_data} = Hibana.Plugins.OAuth.exchange_token(code, config)","ref":"Hibana.Plugins.OAuth.html#module-exchange_token-2"},{"type":"module","title":"fetch_user/2 - Hibana.Plugins.OAuth","doc":"Fetch user profile from provider:\n\n    {:ok, user} = Hibana.Plugins.OAuth.fetch_user(access_token, user_url)","ref":"Hibana.Plugins.OAuth.html#module-fetch_user-2"},{"type":"function","title":"Hibana.Plugins.OAuth.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.OAuth.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.OAuth.exchange_token/2","doc":"Exchange authorization code for access token.","ref":"Hibana.Plugins.OAuth.html#exchange_token/2"},{"type":"function","title":"Hibana.Plugins.OAuth.fetch_user/2","doc":"Fetch user profile from provider.","ref":"Hibana.Plugins.OAuth.html#fetch_user/2"},{"type":"function","title":"Hibana.Plugins.OAuth.generate_authorization_url/2","doc":"Generate OAuth authorization URL for a provider.","ref":"Hibana.Plugins.OAuth.html#generate_authorization_url/2"},{"type":"function","title":"Hibana.Plugins.OAuth.redirect/2","doc":"","ref":"Hibana.Plugins.OAuth.html#redirect/2"},{"type":"function","title":"Hibana.Plugins.OAuth.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.OAuth.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.RateLimiter","doc":"Rate limiting plugin using token bucket algorithm.","ref":"Hibana.Plugins.RateLimiter.html"},{"type":"module","title":"Features - Hibana.Plugins.RateLimiter","doc":"- Token bucket algorithm for smooth rate limiting\n- Per-IP or custom key-based limiting\n- ETS-based storage for high performance\n- Automatic token refill after window expires\n- Configurable key extraction function","ref":"Hibana.Plugins.RateLimiter.html#module-features"},{"type":"module","title":"Usage - Hibana.Plugins.RateLimiter","doc":"# Basic usage - 100 requests per minute per IP\n    plug Hibana.Plugins.RateLimiter\n\n    # Custom configuration\n    plug Hibana.Plugins.RateLimiter,\n      max_requests: 1000,\n      window_ms: 60_000\n\n    # Custom key function (e.g., by user ID from session)\n    plug Hibana.Plugins.RateLimiter,\n      max_requests: 100,\n      window_ms: 60_000,\n      key_fn: &custom_key/1","ref":"Hibana.Plugins.RateLimiter.html#module-usage"},{"type":"module","title":"Options - Hibana.Plugins.RateLimiter","doc":"- `:max_requests` - Maximum requests per window (default: `100`)\n- `:window_ms` - Time window in milliseconds (default: `60_000`)\n- `:storage` - Storage type (default: `:memory` with ETS)\n- `:key_fn` - Custom function to extract rate limit key (default: IP + path)","ref":"Hibana.Plugins.RateLimiter.html#module-options"},{"type":"module","title":"Custom Key Function - Hibana.Plugins.RateLimiter","doc":"Example custom key function:\n\n    def custom_key(conn) do\n      conn.assigns.user_id || conn.remote_ip |> Tuple.to_list() |> Enum.join(\".\")\n    end","ref":"Hibana.Plugins.RateLimiter.html#module-custom-key-function"},{"type":"module","title":"Response - Hibana.Plugins.RateLimiter","doc":"When rate limit is exceeded, returns HTTP 429 with JSON body:\n\n    %{\n      \"error\" => \"Rate limit exceeded\",\n      \"retry_after\" => 60000\n    }","ref":"Hibana.Plugins.RateLimiter.html#module-response"},{"type":"module","title":"ETS Table - Hibana.Plugins.RateLimiter","doc":"Uses `:rate_limiter` ETS table. Ensure it's created at startup:\n\n    :ets.new(:rate_limiter, [:set, :named_table, :public])","ref":"Hibana.Plugins.RateLimiter.html#module-ets-table"},{"type":"function","title":"Hibana.Plugins.RateLimiter.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.RateLimiter.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.RateLimiter.start_link/0","doc":"Start the rate limiter ETS table","ref":"Hibana.Plugins.RateLimiter.html#start_link/0"},{"type":"function","title":"Hibana.Plugins.RateLimiter.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.RateLimiter.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.RequestSigning","doc":"HMAC request signing plugin for API-to-API authentication.","ref":"Hibana.Plugins.RequestSigning.html"},{"type":"module","title":"As a Plug (verify incoming requests) - Hibana.Plugins.RequestSigning","doc":"plug Hibana.Plugins.RequestSigning,\n      secret: \"my-shared-secret\",\n      max_age: 300","ref":"Hibana.Plugins.RequestSigning.html#module-as-a-plug-verify-incoming-requests"},{"type":"module","title":"Signing outgoing requests - Hibana.Plugins.RequestSigning","doc":"headers = Hibana.Plugins.RequestSigning.sign_headers(\n      method: \"POST\",\n      path: \"/api/data\",\n      body: ~s({\"key\":\"value\"}),\n      secret: \"my-shared-secret\"\n    )","ref":"Hibana.Plugins.RequestSigning.html#module-signing-outgoing-requests"},{"type":"module","title":"Options - Hibana.Plugins.RequestSigning","doc":"- `:secret` - Shared secret key used for HMAC signing (required)\n- `:max_age` - Maximum allowed age of a request signature in seconds (default: `300`)\n- `:algorithm` - Hash algorithm for HMAC computation (default: `:sha256`)","ref":"Hibana.Plugins.RequestSigning.html#module-options"},{"type":"function","title":"Hibana.Plugins.RequestSigning.sign/1","doc":"Sign request parameters and return the signature string.","ref":"Hibana.Plugins.RequestSigning.html#sign/1"},{"type":"function","title":"Options - Hibana.Plugins.RequestSigning.sign/1","doc":"- `:method` - HTTP method (required)\n  - `:path` - request path (required)\n  - `:body` - request body (default: \"\")\n  - `:secret` - shared secret (required)\n  - `:timestamp` - override timestamp (default: current time)\n  - `:algorithm` - hash algorithm (default: :sha256)","ref":"Hibana.Plugins.RequestSigning.html#sign/1-options"},{"type":"function","title":"Hibana.Plugins.RequestSigning.sign_headers/1","doc":"Generate signature headers for an outgoing request.\nReturns a list of `{header_name, value}` tuples.","ref":"Hibana.Plugins.RequestSigning.html#sign_headers/1"},{"type":"function","title":"Options - Hibana.Plugins.RequestSigning.sign_headers/1","doc":"- `:method` - HTTP method (required)\n  - `:path` - request path (required)\n  - `:body` - request body (default: \"\")\n  - `:secret` - shared secret (required)\n  - `:timestamp` - override timestamp (default: current time)\n  - `:algorithm` - hash algorithm (default: :sha256)","ref":"Hibana.Plugins.RequestSigning.html#sign_headers/1-options"},{"type":"function","title":"Hibana.Plugins.RequestSigning.verify_signature/1","doc":"Verify a signature against request parameters.\n\nReturns `:ok` or `{:error, reason}`.","ref":"Hibana.Plugins.RequestSigning.html#verify_signature/1"},{"type":"module","title":"Hibana.Plugins.ScopedCORS","doc":"Per-route CORS configuration. Apply different CORS rules to different route groups.","ref":"Hibana.Plugins.ScopedCORS.html"},{"type":"module","title":"Usage - Hibana.Plugins.ScopedCORS","doc":"# In controller\n    def index(conn) do\n      conn = Hibana.Plugins.ScopedCORS.apply(conn,\n        origins: [\"https://app.example.com\"],\n        credentials: true\n      )\n      json(conn, data)\n    end\n\n    # Or as a plug with path matching\n    plug Hibana.Plugins.ScopedCORS,\n      rules: [\n        {\"/api/public/*\", origins: [\"*\"], credentials: false},\n        {\"/api/admin/*\", origins: [\"https://admin.example.com\"], credentials: true},\n        {\"/api/*\", origins: [\"https://app.example.com\"]}\n      ]","ref":"Hibana.Plugins.ScopedCORS.html#module-usage"},{"type":"module","title":"Options - Hibana.Plugins.ScopedCORS","doc":"- `:rules` - List of `{path_pattern, cors_opts}` tuples where `path_pattern` is a string with `*` wildcards and `cors_opts` is a keyword list of CORS settings (default: `[]`)\n- `:default` - Default CORS keyword options applied when no rule matches (default: `[]`)","ref":"Hibana.Plugins.ScopedCORS.html#module-options"},{"type":"function","title":"Hibana.Plugins.ScopedCORS.apply/2","doc":"Apply CORS headers to a connection with given options","ref":"Hibana.Plugins.ScopedCORS.html#apply/2"},{"type":"function","title":"Hibana.Plugins.ScopedCORS.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.ScopedCORS.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.ScopedCORS.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.ScopedCORS.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.TOTP","doc":"Two-factor authentication with TOTP (RFC 6238) and HOTP (RFC 4226).\nCompatible with Google Authenticator and similar apps.","ref":"Hibana.Plugins.TOTP.html"},{"type":"module","title":"Usage - Hibana.Plugins.TOTP","doc":"secret = Hibana.Plugins.TOTP.generate_secret()\n    token = Hibana.Plugins.TOTP.generate_token(secret)\n    :ok = Hibana.Plugins.TOTP.verify(secret, token)\n\n    uri = Hibana.Plugins.TOTP.provisioning_uri(secret, \"user@example.com\", issuer: \"MyApp\")","ref":"Hibana.Plugins.TOTP.html#module-usage"},{"type":"function","title":"Hibana.Plugins.TOTP.generate_secret/1","doc":"Generate a random base32-encoded secret.","ref":"Hibana.Plugins.TOTP.html#generate_secret/1"},{"type":"function","title":"Hibana.Plugins.TOTP.generate_token/2","doc":"Generate the current TOTP token for the given secret.","ref":"Hibana.Plugins.TOTP.html#generate_token/2"},{"type":"function","title":"Options - Hibana.Plugins.TOTP.generate_token/2","doc":"- `:period` - time step in seconds (default: 30)\n  - `:digits` - number of digits (default: 6)\n  - `:algorithm` - hash algorithm (default: :sha)\n  - `:time` - override current time (Unix timestamp)","ref":"Hibana.Plugins.TOTP.html#generate_token/2-options"},{"type":"function","title":"Hibana.Plugins.TOTP.hotp/3","doc":"Generate an HOTP token (RFC 4226).","ref":"Hibana.Plugins.TOTP.html#hotp/3"},{"type":"function","title":"Options - Hibana.Plugins.TOTP.hotp/3","doc":"- `:digits` - number of digits (default: 6)\n  - `:algorithm` - hash algorithm (default: :sha)","ref":"Hibana.Plugins.TOTP.html#hotp/3-options"},{"type":"function","title":"Hibana.Plugins.TOTP.provisioning_uri/3","doc":"Generate an otpauth:// URI for QR code provisioning.","ref":"Hibana.Plugins.TOTP.html#provisioning_uri/3"},{"type":"function","title":"Options - Hibana.Plugins.TOTP.provisioning_uri/3","doc":"- `:issuer` - application name\n  - `:period` - time step (default: 30)\n  - `:digits` - number of digits (default: 6)\n  - `:algorithm` - hash algorithm (default: :sha)","ref":"Hibana.Plugins.TOTP.html#provisioning_uri/3-options"},{"type":"function","title":"Hibana.Plugins.TOTP.verify/3","doc":"Verify a TOTP token against the secret.","ref":"Hibana.Plugins.TOTP.html#verify/3"},{"type":"function","title":"Options - Hibana.Plugins.TOTP.verify/3","doc":"- `:period` - time step in seconds (default: 30)\n  - `:digits` - number of digits (default: 6)\n  - `:algorithm` - hash algorithm (default: :sha)\n  - `:window` - number of time steps to check before/after (default: 1)\n  - `:time` - override current time (Unix timestamp)\n\nReturns `:ok` on success, `{:error, :invalid_token}` on failure.","ref":"Hibana.Plugins.TOTP.html#verify/3-options"},{"type":"module","title":"Hibana.Plugins.APIVersioning","doc":"API Versioning plugin for versioned REST APIs.","ref":"Hibana.Plugins.APIVersioning.html"},{"type":"module","title":"Features - Hibana.Plugins.APIVersioning","doc":"- Multiple versioning strategies (path, header, query)\n- Configurable default version\n- Available in conn.assigns\n- Validates against known versions","ref":"Hibana.Plugins.APIVersioning.html#module-features"},{"type":"module","title":"Usage - Hibana.Plugins.APIVersioning","doc":"# Path-based versioning (default)\n    plug Hibana.Plugins.APIVersioning\n\n    # Multiple strategies\n    plug Hibana.Plugins.APIVersioning,\n      default: \"v1\",\n      strategies: [:path, :header, :query]","ref":"Hibana.Plugins.APIVersioning.html#module-usage"},{"type":"module","title":"Versioning Strategies - Hibana.Plugins.APIVersioning","doc":"","ref":"Hibana.Plugins.APIVersioning.html#module-versioning-strategies"},{"type":"module","title":"Path Strategy (default) - Hibana.Plugins.APIVersioning","doc":"Version in URL path:\n\n    GET /api/v1/users\n    GET /api/v2/users","ref":"Hibana.Plugins.APIVersioning.html#module-path-strategy-default"},{"type":"module","title":"Header Strategy - Hibana.Plugins.APIVersioning","doc":"Version via Accept header:\n\n    Accept: application/vnd.elixir-web.v1+json\n    Accept: application/vnd.elixir-web.v2+json","ref":"Hibana.Plugins.APIVersioning.html#module-header-strategy"},{"type":"module","title":"Query Strategy - Hibana.Plugins.APIVersioning","doc":"Version via query parameter:\n\n    GET /api/users?version=v1","ref":"Hibana.Plugins.APIVersioning.html#module-query-strategy"},{"type":"module","title":"Options - Hibana.Plugins.APIVersioning","doc":"- `:default` - Default API version (default: `\"v1\"`)\n- `:strategies` - List of strategies to use (default: `[:path]`)\n- `:versions` - List of valid versions (default: `[\"v1\", \"v2\"]`)","ref":"Hibana.Plugins.APIVersioning.html#module-options"},{"type":"module","title":"Conn Assignments - Hibana.Plugins.APIVersioning","doc":"After version extraction:\n\n    conn.assigns.api_version  # => \"v2\"","ref":"Hibana.Plugins.APIVersioning.html#module-conn-assignments"},{"type":"module","title":"Module Function - Hibana.Plugins.APIVersioning","doc":"","ref":"Hibana.Plugins.APIVersioning.html#module-module-function"},{"type":"module","title":"get_version/1 - Hibana.Plugins.APIVersioning","doc":"Get the current API version from connection:\n\n    version = Hibana.Plugins.APIVersioning.get_version(conn)","ref":"Hibana.Plugins.APIVersioning.html#module-get_version-1"},{"type":"function","title":"Hibana.Plugins.APIVersioning.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.APIVersioning.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.APIVersioning.get_version/1","doc":"Get the current API version from connection.","ref":"Hibana.Plugins.APIVersioning.html#get_version/1"},{"type":"function","title":"Hibana.Plugins.APIVersioning.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.APIVersioning.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.BodyParser","doc":"Request body parser for JSON and form data.","ref":"Hibana.Plugins.BodyParser.html"},{"type":"module","title":"Features - Hibana.Plugins.BodyParser","doc":"- JSON parsing with configurable decoder\n- URL-encoded form data parsing\n- Automatic content-type detection\n- Parsed data stored in `conn.body_params`","ref":"Hibana.Plugins.BodyParser.html#module-features"},{"type":"module","title":"Usage - Hibana.Plugins.BodyParser","doc":"# Enable JSON and URL-encoded parsing (default)\n    plug Hibana.Plugins.BodyParser\n\n    # Custom configuration\n    plug Hibana.Plugins.BodyParser,\n      parsers: [:json, :urlencoded],\n      json_decoder: Jason","ref":"Hibana.Plugins.BodyParser.html#module-usage"},{"type":"module","title":"Options - Hibana.Plugins.BodyParser","doc":"- `:parsers` - List of enabled parsers (default: `[:json, :urlencoded]`)\n- `:json_decoder` - JSON decoder module (default: `Jason`)","ref":"Hibana.Plugins.BodyParser.html#module-options"},{"type":"module","title":"Parsed Data - Hibana.Plugins.BodyParser","doc":"After parsing, the request body is available in:\n\n    conn.body_params  # Map of parsed body data\n\nExample:\n\n    # POST body: {\"name\": \"John\", \"email\": \"john@example.com\"}\n    conn.body_params[\"name\"]  # => \"John\"","ref":"Hibana.Plugins.BodyParser.html#module-parsed-data"},{"type":"function","title":"Hibana.Plugins.BodyParser.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.BodyParser.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.BodyParser.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.BodyParser.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.Compression","doc":"Response compression plugin supporting gzip and deflate.","ref":"Hibana.Plugins.Compression.html"},{"type":"module","title":"Usage - Hibana.Plugins.Compression","doc":"plug Hibana.Plugins.Compression\n    plug Hibana.Plugins.Compression, level: 6, min_size: 1024","ref":"Hibana.Plugins.Compression.html#module-usage"},{"type":"module","title":"Options - Hibana.Plugins.Compression","doc":"- `:level` - Compression level from 0 (no compression) to 9 (maximum compression), used for deflate encoding (default: `6`)\n- `:min_size` - Minimum response body size in bytes before compression is applied (default: `860`)","ref":"Hibana.Plugins.Compression.html#module-options"},{"type":"function","title":"Hibana.Plugins.Compression.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.Compression.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.Compression.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.Compression.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.ContentNegotiation","doc":"Content Negotiation plugin for format selection (JSON/XML/CSV/etc).","ref":"Hibana.Plugins.ContentNegotiation.html"},{"type":"module","title":"Features - Hibana.Plugins.ContentNegotiation","doc":"- Automatic format selection based on Accept header\n- Supports JSON, XML, HTML, Text, CSV formats\n- Custom format renderer via `render_as/3`\n- Falls back to default format if none matches","ref":"Hibana.Plugins.ContentNegotiation.html#module-features"},{"type":"module","title":"Usage - Hibana.Plugins.ContentNegotiation","doc":"# Enable with JSON only (default)\n    plug Hibana.Plugins.ContentNegotiation\n\n    # Multiple formats\n    plug Hibana.Plugins.ContentNegotiation,\n      formats: [\"json\", \"xml\", \"html\"],\n      default: \"json\"","ref":"Hibana.Plugins.ContentNegotiation.html#module-usage"},{"type":"module","title":"Options - Hibana.Plugins.ContentNegotiation","doc":"- `:formats` - Supported formats (default: `[\"json\"]`)\n- `:default` - Default format (default: `\"json\"`)","ref":"Hibana.Plugins.ContentNegotiation.html#module-options"},{"type":"module","title":"Supported Formats - Hibana.Plugins.ContentNegotiation","doc":"| Format | Content-Type |\n|--------|--------------|\n| json   | application/json |\n| xml    | application/xml |\n| html   | text/html |\n| text   | text/plain |\n| csv    | text/csv |","ref":"Hibana.Plugins.ContentNegotiation.html#module-supported-formats"},{"type":"module","title":"Conn Assignments - Hibana.Plugins.ContentNegotiation","doc":"After negotiation:\n\n    conn.assigns.response_format       # => \"json\"\n    conn.assigns.response_content_type   # => \"application/json\"","ref":"Hibana.Plugins.ContentNegotiation.html#module-conn-assignments"},{"type":"module","title":"Rendering Responses - Hibana.Plugins.ContentNegotiation","doc":"Use `render_as/3` to render in the negotiated format:\n\n    defmodule MyController do\n      use Hibana.Controller\n\n      def index(conn) do\n        data = %{users: [...]}\n        format = conn.assigns.response_format || \"json\"\n        render_as(conn, format, data)\n      end\n    end","ref":"Hibana.Plugins.ContentNegotiation.html#module-rendering-responses"},{"type":"function","title":"Hibana.Plugins.ContentNegotiation.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.ContentNegotiation.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.ContentNegotiation.render_as/3","doc":"","ref":"Hibana.Plugins.ContentNegotiation.html#render_as/3"},{"type":"function","title":"Hibana.Plugins.ContentNegotiation.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.ContentNegotiation.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.I18n","doc":"Built-in internationalization with locale detection from Accept-Language header,\ntranslation storage, and interpolation.","ref":"Hibana.Plugins.I18n.html"},{"type":"module","title":"Usage - Hibana.Plugins.I18n","doc":"plug Hibana.Plugins.I18n, default_locale: \"en\", locales: [\"en\", \"vi\", \"ja\"]\n\n    # Register translations\n    Hibana.Plugins.I18n.put_translations(\"en\", %{\n      \"hello\" => \"Hello, %{name}!\",\n      \"welcome\" => \"Welcome to our app\"\n    })\n\n    Hibana.Plugins.I18n.put_translations(\"vi\", %{\n      \"hello\" => \"Xin chao, %{name}!\",\n      \"welcome\" => \"Chao mung ban den voi ung dung\"\n    })\n\n    # In controller\n    def index(conn) do\n      locale = conn.assigns[:locale]\n      greeting = Hibana.Plugins.I18n.t(locale, \"hello\", name: \"Alice\")\n      json(conn, %{message: greeting})\n    end","ref":"Hibana.Plugins.I18n.html#module-usage"},{"type":"module","title":"Options - Hibana.Plugins.I18n","doc":"- `:default_locale` - Fallback locale when detection fails (default: `\"en\"`)\n- `:locales` - List of supported locale strings (default: `[\"en\"]`)\n- `:detect_from` - Ordered list of sources to detect locale from; valid values are `:header`, `:query`, and `:cookie` (default: `[:header, :query, :cookie]`)","ref":"Hibana.Plugins.I18n.html#module-options"},{"type":"function","title":"Hibana.Plugins.I18n.available_locales/0","doc":"","ref":"Hibana.Plugins.I18n.html#available_locales/0"},{"type":"function","title":"Hibana.Plugins.I18n.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.I18n.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.I18n.put_translations/2","doc":"","ref":"Hibana.Plugins.I18n.html#put_translations/2"},{"type":"function","title":"Hibana.Plugins.I18n.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.I18n.html#start_link/1"},{"type":"function","title":"Hibana.Plugins.I18n.t/3","doc":"","ref":"Hibana.Plugins.I18n.html#t/3"},{"type":"module","title":"Hibana.Plugins.RequestId","doc":"Request ID and tracing plugin for debugging and log correlation.","ref":"Hibana.Plugins.RequestId.html"},{"type":"module","title":"Features - Hibana.Plugins.RequestId","doc":"- Generates unique request IDs for each request\n- Uses existing X-Request-ID header if provided\n- Adds request ID to response headers\n- Available in conn.assigns for application use","ref":"Hibana.Plugins.RequestId.html#module-features"},{"type":"module","title":"Usage - Hibana.Plugins.RequestId","doc":"# Basic usage\n    plug Hibana.Plugins.RequestId\n\n    # With custom header name\n    plug Hibana.Plugins.RequestId, header: \"x-correlation-id\"","ref":"Hibana.Plugins.RequestId.html#module-usage"},{"type":"module","title":"Options - Hibana.Plugins.RequestId","doc":"- `:header` - Request/response header name (default: `\"x-request-id\"`)\n- `:generate_if_missing` - Generate ID if not provided (default: `true`)","ref":"Hibana.Plugins.RequestId.html#module-options"},{"type":"module","title":"Conn Assignments - Hibana.Plugins.RequestId","doc":"conn.assigns.request_id  # => \"a1b2c3d4e5f6g7h8\"","ref":"Hibana.Plugins.RequestId.html#module-conn-assignments"},{"type":"module","title":"Response Header - Hibana.Plugins.RequestId","doc":"Returns the request ID in the configured header:\n\n    X-Request-ID: a1b2c3d4e5f6g7h8","ref":"Hibana.Plugins.RequestId.html#module-response-header"},{"type":"module","title":"ID Format - Hibana.Plugins.RequestId","doc":"16 bytes random data, hex-encoded (32 characters).","ref":"Hibana.Plugins.RequestId.html#module-id-format"},{"type":"function","title":"Hibana.Plugins.RequestId.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.RequestId.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.RequestId.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.RequestId.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.Session","doc":"Session management plugin using encrypted cookies.","ref":"Hibana.Plugins.Session.html"},{"type":"module","title":"Features - Hibana.Plugins.Session","doc":"- Cookie-based session storage\n- Automatic encryption/decryption\n- Plug-and-play session access\n- Automatic session persistence on response","ref":"Hibana.Plugins.Session.html#module-features"},{"type":"module","title":"Usage - Hibana.Plugins.Session","doc":"# Basic usage\n    plug Hibana.Plugins.Session\n\n    # With custom configuration\n    plug Hibana.Plugins.Session,\n      key: \"my_app_session\",\n      secret: \"your-secret-key-at-least-64-bytes\",\n      max_age: 86400 * 7  # 7 days","ref":"Hibana.Plugins.Session.html#module-usage"},{"type":"module","title":"Options - Hibana.Plugins.Session","doc":"- `:store` - Storage type (default: `:cookie`)\n- `:key` - Cookie name (default: `\"hibana_session\"`)\n- `:secret` - Encryption secret (default: `\"secret_key_for_session\"`)\n- `:max_age` - Session lifetime in seconds (default: `86400 * 30`)","ref":"Hibana.Plugins.Session.html#module-options"},{"type":"module","title":"Session Access - Hibana.Plugins.Session","doc":"Use `get_session/2` and `put_session/3` in controllers:\n\n    defmodule MyController do\n      use Hibana.Controller\n\n      def login(conn) do\n        # Store in session\n        put_session(conn, :user_id, user.id)\n        |> redirect(to: \"/dashboard\")\n      end\n\n      def dashboard(conn) do\n        # Read from session\n        user_id = get_session(conn, :user_id)\n        # ...\n      end\n    end","ref":"Hibana.Plugins.Session.html#module-session-access"},{"type":"module","title":"Implementation - Hibana.Plugins.Session","doc":"Sessions are stored in `conn.assigns.__session__` and automatically\npersisted to cookies on response via `register_before_send/2`.","ref":"Hibana.Plugins.Session.html#module-implementation"},{"type":"function","title":"Hibana.Plugins.Session.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.Session.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.Session.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.Session.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.ColorLogger","doc":"Pretty-printed colored request logger with timing breakdown.","ref":"Hibana.Plugins.ColorLogger.html"},{"type":"module","title":"Usage - Hibana.Plugins.ColorLogger","doc":"plug Hibana.Plugins.ColorLogger","ref":"Hibana.Plugins.ColorLogger.html#module-usage"},{"type":"module","title":"Output Example - Hibana.Plugins.ColorLogger","doc":"| GET /api/users\n    | Status: 200 OK\n    | Duration: 12.4ms\n    | Params: %{\"page\" => \"1\"}\n    +-----------------------","ref":"Hibana.Plugins.ColorLogger.html#module-output-example"},{"type":"module","title":"Options - Hibana.Plugins.ColorLogger","doc":"- `:level` - Logger level to use for output (default: `:info`)\n- `:include_params` - Whether to log request parameters (default: `true`)\n- `:include_headers` - Whether to log request headers (default: `false`)","ref":"Hibana.Plugins.ColorLogger.html#module-options"},{"type":"function","title":"Hibana.Plugins.ColorLogger.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.ColorLogger.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.ColorLogger.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.ColorLogger.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.GracefulShutdown","doc":"Graceful shutdown plugin for zero-downtime deployments.","ref":"Hibana.Plugins.GracefulShutdown.html"},{"type":"module","title":"Features - Hibana.Plugins.GracefulShutdown","doc":"- Configurable shutdown timeout\n- Request draining support\n- Process exit signaling\n- Header signaling for load balancers","ref":"Hibana.Plugins.GracefulShutdown.html#module-features"},{"type":"module","title":"Usage - Hibana.Plugins.GracefulShutdown","doc":"# Basic usage\n    plug Hibana.Plugins.GracefulShutdown\n\n    # Custom timeout\n    plug Hibana.Plugins.GracefulShutdown,\n      timeout: 60_000,\n      drain: true","ref":"Hibana.Plugins.GracefulShutdown.html#module-usage"},{"type":"module","title":"Options - Hibana.Plugins.GracefulShutdown","doc":"- `:timeout` - Shutdown timeout in ms (default: `30_000`)\n- `:drain` - Enable request draining (default: `true`)","ref":"Hibana.Plugins.GracefulShutdown.html#module-options"},{"type":"module","title":"Module Functions - Hibana.Plugins.GracefulShutdown","doc":"","ref":"Hibana.Plugins.GracefulShutdown.html#module-module-functions"},{"type":"module","title":"start_shutdown/1 - Hibana.Plugins.GracefulShutdown","doc":"Initiate graceful shutdown:\n\n    Hibana.Plugins.GracefulShutdown.start_shutdown(30_000)","ref":"Hibana.Plugins.GracefulShutdown.html#module-start_shutdown-1"},{"type":"module","title":"drain_requests/1 - Hibana.Plugins.GracefulShutdown","doc":"Wait for in-flight requests to complete:\n\n    Hibana.Plugins.GracefulShutdown.drain_requests(30_000)","ref":"Hibana.Plugins.GracefulShutdown.html#module-drain_requests-1"},{"type":"module","title":"notify_shutdown/0 - Hibana.Plugins.GracefulShutdown","doc":"Signal shutdown to all processes:\n\n    Hibana.Plugins.GracefulShutdown.notify_shutdown()","ref":"Hibana.Plugins.GracefulShutdown.html#module-notify_shutdown-0"},{"type":"module","title":"Shutdown Sequence - Hibana.Plugins.GracefulShutdown","doc":"1. Receive SIGTERM\n2. Stop accepting new requests\n3. Drain existing requests (wait for completion)\n4. Timeout if requests take too long\n5. Exit process","ref":"Hibana.Plugins.GracefulShutdown.html#module-shutdown-sequence"},{"type":"module","title":"Response Header - Hibana.Plugins.GracefulShutdown","doc":"Adds header to indicate shutdown capability:\n\n    X-Shutdown-Timeout: 30000","ref":"Hibana.Plugins.GracefulShutdown.html#module-response-header"},{"type":"function","title":"Hibana.Plugins.GracefulShutdown.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.GracefulShutdown.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.GracefulShutdown.drain_requests/1","doc":"Drain remaining requests before shutdown.","ref":"Hibana.Plugins.GracefulShutdown.html#drain_requests/1"},{"type":"function","title":"Hibana.Plugins.GracefulShutdown.notify_shutdown/0","doc":"Notify shutdown to all processes.","ref":"Hibana.Plugins.GracefulShutdown.html#notify_shutdown/0"},{"type":"function","title":"Hibana.Plugins.GracefulShutdown.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.GracefulShutdown.html#start_link/1"},{"type":"function","title":"Hibana.Plugins.GracefulShutdown.start_shutdown/1","doc":"Start graceful shutdown process.","ref":"Hibana.Plugins.GracefulShutdown.html#start_shutdown/1"},{"type":"module","title":"Hibana.Plugins.HealthCheck","doc":"Health check endpoint plugin for load balancers and orchestration.","ref":"Hibana.Plugins.HealthCheck.html"},{"type":"module","title":"Features - Hibana.Plugins.HealthCheck","doc":"- Built-in system health checks (memory, processes, uptime)\n- Custom health check registration\n- Prometheus-compatible response format\n- Configurable health endpoint path","ref":"Hibana.Plugins.HealthCheck.html#module-features"},{"type":"module","title":"Usage - Hibana.Plugins.HealthCheck","doc":"# Basic usage (health endpoint at /health)\n    plug Hibana.Plugins.HealthCheck\n\n    # With custom path\n    plug Hibana.Plugins.HealthCheck, path: \"/api/health\"","ref":"Hibana.Plugins.HealthCheck.html#module-usage"},{"type":"module","title":"Response Format - Hibana.Plugins.HealthCheck","doc":"Returns JSON:\n\n    {\n      \"status\": \"healthy\",\n      \"timestamp\": 1234567890,\n      \"checks\": {\n        \"memory\": \"ok\",\n        \"processes\": \"ok\",\n        \"uptime\": \"ok\"\n      }\n    }\n\n- HTTP 200: All checks pass\n- HTTP 503: One or more checks fail","ref":"Hibana.Plugins.HealthCheck.html#module-response-format"},{"type":"module","title":"Built-in Checks - Hibana.Plugins.HealthCheck","doc":"- **memory** - Checks if memory usage is below threshold\n- **processes** - Checks if process count is below threshold\n- **uptime** - Always returns :ok","ref":"Hibana.Plugins.HealthCheck.html#module-built-in-checks"},{"type":"module","title":"Custom Checks - Hibana.Plugins.HealthCheck","doc":"Register custom health checks:\n\n    Hibana.Plugins.HealthCheck.register_check(:database, fn ->\n      case DB.check_connection() do\n        :ok -> :ok\n        _ -> :error\n      end\n    end)","ref":"Hibana.Plugins.HealthCheck.html#module-custom-checks"},{"type":"module","title":"Options - Hibana.Plugins.HealthCheck","doc":"- `:path` - Health endpoint path (default: `\"/health\"`)\n- `:checks` - List of additional checks to run","ref":"Hibana.Plugins.HealthCheck.html#module-options"},{"type":"module","title":"Response Headers - Hibana.Plugins.HealthCheck","doc":"- `x-health-status` - \"ok\" or \"error\"\n- `content-type` - \"application/json\"","ref":"Hibana.Plugins.HealthCheck.html#module-response-headers"},{"type":"function","title":"Hibana.Plugins.HealthCheck.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.HealthCheck.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.HealthCheck.register_check/2","doc":"Register a custom health check.","ref":"Hibana.Plugins.HealthCheck.html#register_check/2"},{"type":"function","title":"Hibana.Plugins.HealthCheck.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.HealthCheck.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.LiveDashboard","doc":"System dashboard plugin for Hibana, similar to Phoenix LiveDashboard.\n\nProvides a dark-themed dashboard with auto-refresh (every 3 seconds) showing:\n- System overview (memory, processes, ports, schedulers, uptime)\n- Process list (top 100 by memory)\n- ETS tables\n- Ports\n- OTP applications\n- Memory allocation details","ref":"Hibana.Plugins.LiveDashboard.html"},{"type":"module","title":"Usage - Hibana.Plugins.LiveDashboard","doc":"plug Hibana.Plugins.LiveDashboard, path: \"/_dashboard\"","ref":"Hibana.Plugins.LiveDashboard.html#module-usage"},{"type":"module","title":"Options - Hibana.Plugins.LiveDashboard","doc":"- `:path` - Base URL path for the dashboard (default: `\"/_dashboard\"`)\n- `:auth` - A function `(Plug.Conn.t() -> boolean())` that checks authorization; when `nil`, the dashboard is publicly accessible (default: `nil`)","ref":"Hibana.Plugins.LiveDashboard.html#module-options"},{"type":"function","title":"Hibana.Plugins.LiveDashboard.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.LiveDashboard.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.LiveDashboard.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.LiveDashboard.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.Logger","doc":"Request/Response logger plugin.","ref":"Hibana.Plugins.Logger.html"},{"type":"module","title":"Features - Hibana.Plugins.Logger","doc":"- Request timing (start to finish)\n- Status code-based log levels\n- Configurable log level\n- Color-coded output support","ref":"Hibana.Plugins.Logger.html#module-features"},{"type":"module","title":"Usage - Hibana.Plugins.Logger","doc":"# Basic usage\n    plug Hibana.Plugins.Logger\n\n    # With custom log level\n    plug Hibana.Plugins.Logger, log_level: :debug","ref":"Hibana.Plugins.Logger.html#module-usage"},{"type":"module","title":"Log Format - Hibana.Plugins.Logger","doc":"[GET] /users 200 (45ms)\n    [POST] /users 201 (120ms)\n    [GET] /users/abc 404 (12ms)\n    [GET] /api/users 500 (2345ms)","ref":"Hibana.Plugins.Logger.html#module-log-format"},{"type":"module","title":"Log Levels by Status Code - Hibana.Plugins.Logger","doc":"- **200-399**: `:info` level\n- **400-499**: `:warning` level (client errors)\n- **500+**: `:error` level (server errors)","ref":"Hibana.Plugins.Logger.html#module-log-levels-by-status-code"},{"type":"module","title":"Options - Hibana.Plugins.Logger","doc":"- `:log_level` - Minimum log level (default: `:info`)","ref":"Hibana.Plugins.Logger.html#module-options"},{"type":"module","title":"Example Output - Hibana.Plugins.Logger","doc":"[info]  [GET] /api/users 200 (45ms)\n    [warn]  [GET] /api/users/invalid 404 (12ms)\n    [error] [POST] /api/users 500 (2345ms)","ref":"Hibana.Plugins.Logger.html#module-example-output"},{"type":"function","title":"Hibana.Plugins.Logger.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.Logger.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.Metrics","doc":"Metrics and Telemetry plugin for monitoring and observability.","ref":"Hibana.Plugins.Metrics.html"},{"type":"module","title":"Features - Hibana.Plugins.Metrics","doc":"- Request duration tracking via :telemetry\n- Request counting by method, path, and status\n- Prometheus-compatible metrics endpoint\n- Zero-configuration defaults","ref":"Hibana.Plugins.Metrics.html#module-features"},{"type":"module","title":"Usage - Hibana.Plugins.Metrics","doc":"# Basic usage (metrics at /metrics)\n    plug Hibana.Plugins.Metrics\n\n    # With custom endpoint\n    plug Hibana.Plugins.Metrics, endpoint: \"/admin/metrics\"","ref":"Hibana.Plugins.Metrics.html#module-usage"},{"type":"module","title":"Telemetry Events - Hibana.Plugins.Metrics","doc":"Emits the following :telemetry events:\n\n### [:hibana, :request, :duration]\nFired on each request completion.\n\n    :telemetry.execute(\n      [:hibana, :request, :duration],\n      %{duration: 123},\n      %{method: \"GET\", path: \"/users\", status: 200}\n    )\n\n### [:hibana, :request, :total]\nCounter incremented on each request.\n\n    :telemetry.execute(\n      [:hibana, :request, :total],\n      %{count: 1},\n      %{method: \"GET\", path: \"/users\", status: 200}\n    )","ref":"Hibana.Plugins.Metrics.html#module-telemetry-events"},{"type":"module","title":"Prometheus Endpoint - Hibana.Plugins.Metrics","doc":"GET /metrics returns Prometheus-formatted metrics:\n\n    # HELP hibana_requests_total Total requests\n    # TYPE hibana_requests_total counter\n    hibana_requests_total 1234\n\n    # HELP hibana_request_duration_ms Request duration\n    # TYPE hibana_request_duration_ms histogram\n    hibana_request_duration_ms_count 1234","ref":"Hibana.Plugins.Metrics.html#module-prometheus-endpoint"},{"type":"module","title":"Options - Hibana.Plugins.Metrics","doc":"- `:enabled` - Enable/disable metrics (default: `true`)\n- `:endpoint` - Metrics endpoint path (default: `\"/metrics\"`)","ref":"Hibana.Plugins.Metrics.html#module-options"},{"type":"module","title":"Integration with Prometheus - Hibana.Plugins.Metrics","doc":"Can be scraped by Prometheus:\n\n    scrape_configs:\n      - job_name: 'hibana'\n        static_configs:\n          - targets: ['localhost:4000']\n        metrics_path: '/metrics'","ref":"Hibana.Plugins.Metrics.html#module-integration-with-prometheus"},{"type":"function","title":"Hibana.Plugins.Metrics.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.Metrics.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.Metrics.setup/0","doc":"","ref":"Hibana.Plugins.Metrics.html#setup/0"},{"type":"function","title":"Hibana.Plugins.Metrics.start_link/0","doc":"","ref":"Hibana.Plugins.Metrics.html#start_link/0"},{"type":"function","title":"Hibana.Plugins.Metrics.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.Metrics.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.TelemetryDashboard","doc":"Built-in telemetry dashboard showing live metrics via an HTML page.","ref":"Hibana.Plugins.TelemetryDashboard.html"},{"type":"module","title":"Usage - Hibana.Plugins.TelemetryDashboard","doc":"plug Hibana.Plugins.TelemetryDashboard, path: \"/dashboard\"","ref":"Hibana.Plugins.TelemetryDashboard.html#module-usage"},{"type":"module","title":"Dashboard Shows - Hibana.Plugins.TelemetryDashboard","doc":"- Request count, rate, avg duration\n- Memory usage, process count\n- Node info, uptime\n- Queue depth (if PersistentQueue running)","ref":"Hibana.Plugins.TelemetryDashboard.html#module-dashboard-shows"},{"type":"module","title":"Options - Hibana.Plugins.TelemetryDashboard","doc":"- `:path` - URL path for the dashboard page (default: `\"/dashboard\"`)\n- `:auth` - A function `(Plug.Conn.t() -> boolean())` that checks authorization; when `nil`, the dashboard is publicly accessible (default: `nil`)","ref":"Hibana.Plugins.TelemetryDashboard.html#module-options"},{"type":"function","title":"Hibana.Plugins.TelemetryDashboard.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.TelemetryDashboard.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.TelemetryDashboard.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.TelemetryDashboard.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.Cache","doc":"ETS-based caching plugin with TTL and automatic expiration.","ref":"Hibana.Plugins.Cache.html"},{"type":"module","title":"Features - Hibana.Plugins.Cache","doc":"- High-performance ETS storage\n- TTL (Time-To-Live) support in milliseconds\n- Automatic cleanup of expired entries\n- Cache-aside pattern support with `get_or_compute`\n- Concurrent read/write support","ref":"Hibana.Plugins.Cache.html#module-features"},{"type":"module","title":"Usage - Hibana.Plugins.Cache","doc":"# Enable cache plug\n    plug Hibana.Plugins.Cache\n\n    # With custom TTL (5 minutes default)\n    plug Hibana.Plugins.Cache, ttl: 300_000","ref":"Hibana.Plugins.Cache.html#module-usage"},{"type":"module","title":"Module Functions - Hibana.Plugins.Cache","doc":"","ref":"Hibana.Plugins.Cache.html#module-module-functions"},{"type":"module","title":"get/1 - Hibana.Plugins.Cache","doc":"Get a value from cache:\n\n    case Hibana.Plugins.Cache.get(\"user:123\") do\n      {:ok, nil} -> # cache miss\n      {:ok, user} -> # cache hit\n    end","ref":"Hibana.Plugins.Cache.html#module-get-1"},{"type":"module","title":"set/2-3 - Hibana.Plugins.Cache","doc":"Set a value with TTL:\n\n    Hibana.Plugins.Cache.set(\"user:123\", user_data, ttl: 60_000)","ref":"Hibana.Plugins.Cache.html#module-set-2-3"},{"type":"module","title":"get_or_compute/3 - Hibana.Plugins.Cache","doc":"Cache-aside pattern:\n\n    {:ok, user} = Hibana.Plugins.Cache.get_or_compute(\n      \"user:123\",\n      300_000,\n      fn -> Database.fetch_user(123) end\n    )","ref":"Hibana.Plugins.Cache.html#module-get_or_compute-3"},{"type":"module","title":"delete/1 - Hibana.Plugins.Cache","doc":"Delete a specific key:\n\n    Hibana.Plugins.Cache.delete(\"user:123\")","ref":"Hibana.Plugins.Cache.html#module-delete-1"},{"type":"module","title":"clear/0 - Hibana.Plugins.Cache","doc":"Clear all cache entries:\n\n    Hibana.Plugins.Cache.clear()","ref":"Hibana.Plugins.Cache.html#module-clear-0"},{"type":"module","title":"stats/0 - Hibana.Plugins.Cache","doc":"Get cache statistics:\n\n    Hibana.Plugins.Cache.stats()\n    # => %{Size: 100, memory: 10240}","ref":"Hibana.Plugins.Cache.html#module-stats-0"},{"type":"module","title":"cleanup/0 - Hibana.Plugins.Cache","doc":"Manually trigger cleanup of expired entries:\n\n    Hibana.Plugins.Cache.cleanup()","ref":"Hibana.Plugins.Cache.html#module-cleanup-0"},{"type":"module","title":"Options - Hibana.Plugins.Cache","doc":"- `:ttl` - Default TTL in milliseconds (default: `300_000` = 5 minutes)\n- `:max_size` - Maximum entries (default: `1000`)","ref":"Hibana.Plugins.Cache.html#module-options"},{"type":"module","title":"ETS Table - Hibana.Plugins.Cache","doc":"Uses `:hibana_cache` named ETS table with public access.\nTable is created on `start_link/0`.","ref":"Hibana.Plugins.Cache.html#module-ets-table"},{"type":"function","title":"Hibana.Plugins.Cache.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.Cache.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.Cache.cleanup/0","doc":"Clean up expired entries.","ref":"Hibana.Plugins.Cache.html#cleanup/0"},{"type":"function","title":"Hibana.Plugins.Cache.clear/0","doc":"Clear all cache entries.","ref":"Hibana.Plugins.Cache.html#clear/0"},{"type":"function","title":"Hibana.Plugins.Cache.delete/1","doc":"Delete a key from cache.","ref":"Hibana.Plugins.Cache.html#delete/1"},{"type":"function","title":"Hibana.Plugins.Cache.exists?/1","doc":"Check if a key exists.","ref":"Hibana.Plugins.Cache.html#exists?/1"},{"type":"function","title":"Hibana.Plugins.Cache.get/1","doc":"Get a value from cache.","ref":"Hibana.Plugins.Cache.html#get/1"},{"type":"function","title":"Hibana.Plugins.Cache.get_or_compute/3","doc":"Get or compute a value.","ref":"Hibana.Plugins.Cache.html#get_or_compute/3"},{"type":"function","title":"Hibana.Plugins.Cache.set/3","doc":"Set a value in cache with TTL.","ref":"Hibana.Plugins.Cache.html#set/3"},{"type":"function","title":"Hibana.Plugins.Cache.start_link/0","doc":"","ref":"Hibana.Plugins.Cache.html#start_link/0"},{"type":"function","title":"Hibana.Plugins.Cache.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.Cache.html#start_link/1"},{"type":"function","title":"Hibana.Plugins.Cache.stats/0","doc":"Get cache statistics.","ref":"Hibana.Plugins.Cache.html#stats/0"},{"type":"module","title":"Hibana.Plugins.GraphQL","doc":"GraphQL plugin for query resolution and playground.","ref":"Hibana.Plugins.GraphQL.html"},{"type":"module","title":"Features - Hibana.Plugins.GraphQL","doc":"- POST /graphql - Execute GraphQL queries\n- GET /graphql - Schema introspection\n- GraphQL Playground (optional)","ref":"Hibana.Plugins.GraphQL.html#module-features"},{"type":"module","title":"Usage - Hibana.Plugins.GraphQL","doc":"plug Hibana.Plugins.GraphQL,\n      schema: MyApp.Schema,\n      playground: true","ref":"Hibana.Plugins.GraphQL.html#module-usage"},{"type":"module","title":"Endpoints - Hibana.Plugins.GraphQL","doc":"","ref":"Hibana.Plugins.GraphQL.html#module-endpoints"},{"type":"module","title":"POST /graphql - Hibana.Plugins.GraphQL","doc":"Execute GraphQL queries:\n\n    curl -X POST http://localhost:4000/graphql       -H \"Content-Type: application/json\"       -d '{\"query\": \"{ users { id name } }\"}'","ref":"Hibana.Plugins.GraphQL.html#module-post-graphql"},{"type":"module","title":"GET /graphql - Hibana.Plugins.GraphQL","doc":"Schema introspection JSON:\n\n    curl http://localhost:4000/graphql","ref":"Hibana.Plugins.GraphQL.html#module-get-graphql"},{"type":"module","title":"GET /graphql (with playground enabled) - Hibana.Plugins.GraphQL","doc":"Interactive GraphQL Playground:\n\n    http://localhost:4000/graphql","ref":"Hibana.Plugins.GraphQL.html#module-get-graphql-with-playground-enabled"},{"type":"module","title":"Options - Hibana.Plugins.GraphQL","doc":"- `:schema` - GraphQL schema module (required)\n- `:playground` - Enable GraphQL Playground (default: `false`)\n- `:json_opts` - Options for JSON encoding","ref":"Hibana.Plugins.GraphQL.html#module-options"},{"type":"module","title":"Module Functions - Hibana.Plugins.GraphQL","doc":"","ref":"Hibana.Plugins.GraphQL.html#module-module-functions"},{"type":"module","title":"execute/4 - Hibana.Plugins.GraphQL","doc":"Execute a GraphQL query programmatically:\n\n    result = Hibana.Plugins.GraphQL.execute(\n      schema,\n      \"{ users { id name } }\",\n      %{},\n      nil\n    )","ref":"Hibana.Plugins.GraphQL.html#module-execute-4"},{"type":"module","title":"Request Format - Hibana.Plugins.GraphQL","doc":"{\n      \"query\": \"query($id: ID!) { user(id: $id) { name } }\",\n      \"variables\": {\"id\": \"123\"},\n      \"operationName\": \"MyQuery\"\n    }","ref":"Hibana.Plugins.GraphQL.html#module-request-format"},{"type":"function","title":"Hibana.Plugins.GraphQL.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.GraphQL.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.GraphQL.execute/4","doc":"Execute a GraphQL query against a schema.","ref":"Hibana.Plugins.GraphQL.html#execute/4"},{"type":"function","title":"Hibana.Plugins.GraphQL.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.GraphQL.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.OTPCache","doc":"OTP-based in-memory cache plugin.\n\nThis module delegates to `Hibana.OTPCache`.\nSee `Hibana.OTPCache` for full documentation.","ref":"Hibana.Plugins.OTPCache.html"},{"type":"module","title":"Usage - Hibana.Plugins.OTPCache","doc":"# Start the cache\n    Hibana.Plugins.OTPCache.start_link(name: :my_cache)\n\n    # Set/Get values\n    Hibana.Plugins.OTPCache.put(:my_cache, \"key\", \"value\", ttl: 60_000)\n    Hibana.Plugins.OTPCache.get(:my_cache, \"key\")","ref":"Hibana.Plugins.OTPCache.html#module-usage"},{"type":"module","title":"Options - Hibana.Plugins.OTPCache","doc":"Options are passed through to `Hibana.OTPCache.start_link/1`. See `Hibana.OTPCache` for the full list of supported options.","ref":"Hibana.Plugins.OTPCache.html#module-options"},{"type":"function","title":"Hibana.Plugins.OTPCache.clear/1","doc":"See  Hibana.OTPCache.clear/1 .","ref":"Hibana.Plugins.OTPCache.html#clear/1"},{"type":"function","title":"Hibana.Plugins.OTPCache.delete/2","doc":"See  Hibana.OTPCache.delete/2 .","ref":"Hibana.Plugins.OTPCache.html#delete/2"},{"type":"function","title":"Hibana.Plugins.OTPCache.exists?/2","doc":"See  Hibana.OTPCache.exists?/2 .","ref":"Hibana.Plugins.OTPCache.html#exists?/2"},{"type":"function","title":"Hibana.Plugins.OTPCache.get/2","doc":"See  Hibana.OTPCache.get/2 .","ref":"Hibana.Plugins.OTPCache.html#get/2"},{"type":"function","title":"Hibana.Plugins.OTPCache.get_or_compute/4","doc":"See  Hibana.OTPCache.get_or_compute/4 .","ref":"Hibana.Plugins.OTPCache.html#get_or_compute/4"},{"type":"function","title":"Hibana.Plugins.OTPCache.put/4","doc":"See  Hibana.OTPCache.put/4 .","ref":"Hibana.Plugins.OTPCache.html#put/4"},{"type":"function","title":"Hibana.Plugins.OTPCache.start_link/1","doc":"See  Hibana.OTPCache.start_link/1 .","ref":"Hibana.Plugins.OTPCache.html#start_link/1"},{"type":"function","title":"Hibana.Plugins.OTPCache.stats/1","doc":"See  Hibana.OTPCache.stats/1 .","ref":"Hibana.Plugins.OTPCache.html#stats/1"},{"type":"module","title":"Hibana.Plugins.SEO","doc":"Comprehensive SEO plugin for Hibana.\n\nProvides meta tags, OpenGraph, Twitter Cards, JSON-LD structured data,\nsitemap.xml generation, and robots.txt generation.","ref":"Hibana.Plugins.SEO.html"},{"type":"module","title":"Usage - Hibana.Plugins.SEO","doc":"plug Hibana.Plugins.SEO,\n      sitemap_urls: [...],\n      robots: [allow: [\"/\"], disallow: [\"/admin\"], sitemap: \"https://example.com/sitemap.xml\"]","ref":"Hibana.Plugins.SEO.html#module-usage"},{"type":"module","title":"In controllers - Hibana.Plugins.SEO","doc":"conn\n    |> SEO.meta(title: \"My Page\", description: \"A great page\")\n    |> SEO.open_graph(title: \"My Page\", type: \"website\", image: \"https://example.com/img.png\")\n    |> SEO.twitter_card(card: \"summary_large_image\", site: \"@mysite\")\n    |> SEO.json_ld(%{\"@context\" => \"https://schema.org\", \"@type\" => \"WebPage\", \"name\" => \"My Page\"})\n\nThen in your template:\n\n    <%= SEO.render_head(conn) %>","ref":"Hibana.Plugins.SEO.html#module-in-controllers"},{"type":"module","title":"Options - Hibana.Plugins.SEO","doc":"When used as a plug, the following options control automatic serving of SEO files:\n\n- `:sitemap_urls` - List of URL maps for sitemap.xml generation; each map should have `:loc` (required), and optionally `:priority`, `:changefreq`, `:lastmod` (default: `[]`)\n- `:robots` - Keyword list of robots.txt options (`:user_agent`, `:allow`, `:disallow`, `:sitemap`, `:crawl_delay`) (default: `[]`)","ref":"Hibana.Plugins.SEO.html#module-options"},{"type":"module","title":"Available Functions - Hibana.Plugins.SEO","doc":"- `meta/2` - Set standard meta tags (`:title`, `:description`, `:keywords`, `:canonical`, `:robots`)\n- `open_graph/2` - Set OpenGraph tags (`:title`, `:type`, `:url`, `:image`, `:description`, `:site_name`, `:locale`)\n- `twitter_card/2` - Set Twitter Card tags (`:card`, `:site`, `:creator`, `:title`, `:description`, `:image`)\n- `json_ld/2` - Add JSON-LD structured data\n- `render_head/1` - Render all SEO tags as HTML for inclusion in ` `\n- `generate_sitemap/1` - Generate XML sitemap from URL maps\n- `generate_robots/1` - Generate robots.txt content","ref":"Hibana.Plugins.SEO.html#module-available-functions"},{"type":"function","title":"Hibana.Plugins.SEO.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.SEO.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.SEO.generate_robots/1","doc":"Generate robots.txt content.\n\nOptions:\n- :user_agent - User-Agent string (default \"*\")\n- :allow - list of allowed paths\n- :disallow - list of disallowed paths\n- :sitemap - sitemap URL\n- :crawl_delay - crawl delay in seconds","ref":"Hibana.Plugins.SEO.html#generate_robots/1"},{"type":"function","title":"Hibana.Plugins.SEO.generate_sitemap/1","doc":"Generate an XML sitemap from a list of URL maps.\n\nEach URL map should have: :loc (required), :priority, :changefreq, :lastmod","ref":"Hibana.Plugins.SEO.html#generate_sitemap/1"},{"type":"function","title":"Example - Hibana.Plugins.SEO.generate_sitemap/1","doc":"SEO.generate_sitemap([\n      %{loc: \"https://example.com/\", priority: 1.0, changefreq: \"daily\"},\n      %{loc: \"https://example.com/about\", priority: 0.8, changefreq: \"monthly\"}\n    ])","ref":"Hibana.Plugins.SEO.html#generate_sitemap/1-example"},{"type":"function","title":"Hibana.Plugins.SEO.json_ld/2","doc":"Add JSON-LD structured data (schema.org) to the connection.\nCan be called multiple times to add multiple JSON-LD blocks.","ref":"Hibana.Plugins.SEO.html#json_ld/2"},{"type":"function","title":"Hibana.Plugins.SEO.meta/2","doc":"Set standard meta tags on the connection.\n\nOptions: :title, :description, :keywords, :canonical, :robots","ref":"Hibana.Plugins.SEO.html#meta/2"},{"type":"function","title":"Hibana.Plugins.SEO.open_graph/2","doc":"Set OpenGraph (og:*) tags on the connection.\n\nOptions: :title, :type, :url, :image, :description, :site_name, :locale","ref":"Hibana.Plugins.SEO.html#open_graph/2"},{"type":"function","title":"Hibana.Plugins.SEO.render_head/1","doc":"Render all SEO tags as an HTML string suitable for inclusion in  .","ref":"Hibana.Plugins.SEO.html#render_head/1"},{"type":"function","title":"Hibana.Plugins.SEO.serve_seo_files/2","doc":"Plug that serves /sitemap.xml and /robots.txt.\n\nOptions:\n- :sitemap_urls - list of URL maps for sitemap generation\n- :robots - keyword list of robots.txt options","ref":"Hibana.Plugins.SEO.html#serve_seo_files/2"},{"type":"function","title":"Hibana.Plugins.SEO.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.SEO.html#start_link/1"},{"type":"function","title":"Hibana.Plugins.SEO.twitter_card/2","doc":"Set Twitter Card (twitter:*) tags on the connection.\n\nOptions: :card, :site, :creator, :title, :description, :image","ref":"Hibana.Plugins.SEO.html#twitter_card/2"},{"type":"module","title":"Hibana.Plugins.Search","doc":"Meilisearch search plugin for Hibana.\n\nProvides a full Meilisearch HTTP client and a plug endpoint for searching.","ref":"Hibana.Plugins.Search.html"},{"type":"module","title":"Configuration - Hibana.Plugins.Search","doc":"Hibana.Plugins.Search.configure(\n      url: \"http://localhost:7700\",\n      api_key: \"your-master-key\"\n    )","ref":"Hibana.Plugins.Search.html#module-configuration"},{"type":"module","title":"As a Plug - Hibana.Plugins.Search","doc":"plug Hibana.Plugins.Search, path: \"/search\"\n\nThis serves GET /search?q=query&index=idx&limit=20","ref":"Hibana.Plugins.Search.html#module-as-a-plug"},{"type":"module","title":"Options - Hibana.Plugins.Search","doc":"","ref":"Hibana.Plugins.Search.html#module-options"},{"type":"module","title":"Plug options (passed to plug) - Hibana.Plugins.Search","doc":"- `:path` - URL path for the search endpoint (default: `\"/search\"`)","ref":"Hibana.Plugins.Search.html#module-plug-options-passed-to-plug"},{"type":"module","title":"Configuration options (passed to configure/1) - Hibana.Plugins.Search","doc":"- `:url` - Meilisearch server URL (default: `\"http://localhost:7700\"`)\n- `:api_key` - API key for Meilisearch authentication (default: `nil`)","ref":"Hibana.Plugins.Search.html#module-configuration-options-passed-to-configure-1"},{"type":"function","title":"Hibana.Plugins.Search.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.Search.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.Search.configure/1","doc":"Configure the Meilisearch connection.\n\nOptions:\n- :url - Meilisearch server URL (default \"http://localhost:7700\")\n- :api_key - API key for authentication","ref":"Hibana.Plugins.Search.html#configure/1"},{"type":"function","title":"Hibana.Plugins.Search.create_index/2","doc":"Create a new index.\n\nOptions:\n- :primary_key - primary key field name","ref":"Hibana.Plugins.Search.html#create_index/2"},{"type":"function","title":"Hibana.Plugins.Search.delete_all_documents/1","doc":"Delete all documents in an index.","ref":"Hibana.Plugins.Search.html#delete_all_documents/1"},{"type":"function","title":"Hibana.Plugins.Search.delete_document/2","doc":"Delete a single document by ID.","ref":"Hibana.Plugins.Search.html#delete_document/2"},{"type":"function","title":"Hibana.Plugins.Search.delete_index/1","doc":"Delete an index.","ref":"Hibana.Plugins.Search.html#delete_index/1"},{"type":"function","title":"Hibana.Plugins.Search.get_document/2","doc":"Get a single document by ID.","ref":"Hibana.Plugins.Search.html#get_document/2"},{"type":"function","title":"Hibana.Plugins.Search.health/0","doc":"Check Meilisearch health.","ref":"Hibana.Plugins.Search.html#health/0"},{"type":"function","title":"Hibana.Plugins.Search.index/3","doc":"Index (add or replace) documents into an index.","ref":"Hibana.Plugins.Search.html#index/3"},{"type":"function","title":"Hibana.Plugins.Search.search/3","doc":"Search an index.\n\nOptions:\n- :filter - filter expression\n- :sort - list of sort rules\n- :limit - max results (default 20)\n- :offset - result offset (default 0)\n- :facets - list of facet fields\n- :attributes_to_retrieve - list of attributes to return\n- :attributes_to_highlight - list of attributes to highlight","ref":"Hibana.Plugins.Search.html#search/3"},{"type":"function","title":"Hibana.Plugins.Search.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.Search.html#start_link/1"},{"type":"function","title":"Hibana.Plugins.Search.stats/1","doc":"Get stats for an index.","ref":"Hibana.Plugins.Search.html#stats/1"},{"type":"function","title":"Hibana.Plugins.Search.update_documents/2","doc":"Update documents in an index (partial update).","ref":"Hibana.Plugins.Search.html#update_documents/2"},{"type":"function","title":"Hibana.Plugins.Search.update_settings/2","doc":"Update index settings.\n\nSettings map can include:\n- searchableAttributes\n- filterableAttributes\n- sortableAttributes\n- displayedAttributes\n- rankingRules\n- stopWords\n- synonyms","ref":"Hibana.Plugins.Search.html#update_settings/2"},{"type":"module","title":"Hibana.Plugins.Static","doc":"Static file serving plugin for serving files from disk.","ref":"Hibana.Plugins.Static.html"},{"type":"module","title":"Features - Hibana.Plugins.Static","doc":"- Serves files from configured directory\n- Automatic content-type detection\n- Cache control headers in production\n- Gzip support (optional)\n- Security: does not serve files outside root","ref":"Hibana.Plugins.Static.html#module-features"},{"type":"module","title":"Usage - Hibana.Plugins.Static","doc":"# Serve from priv/static at root\n    plug Hibana.Plugins.Static, at: \"/\", from: \"priv/static\"\n\n    # Serve at /public prefix\n    plug Hibana.Plugins.Static, at: \"/public\", from: \"priv/static\"","ref":"Hibana.Plugins.Static.html#module-usage"},{"type":"module","title":"Options - Hibana.Plugins.Static","doc":"- `:at` - URL prefix to serve (default: `\"/\"`)\n- `:from` - Directory to serve files from (default: `\"priv/static\"`)\n- `:gzip` - Enable gzip support (default: `false`)\n- `:cache_headers` - Add cache headers (default: `true`)","ref":"Hibana.Plugins.Static.html#module-options"},{"type":"module","title":"Caching - Hibana.Plugins.Static","doc":"In production (`MIX_ENV=prod`), adds cache headers:\n\n    Cache-Control: public, max-age=3600\n\nIn development, no caching.","ref":"Hibana.Plugins.Static.html#module-caching"},{"type":"module","title":"Supported Content-Types - Hibana.Plugins.Static","doc":"- HTML, CSS, JS, JSON\n- Images (PNG, JPG, GIF, SVG, ICO)\n- Fonts (WOFF, WOFF2, TTF, EOT)\n- PDF, TXT, and binary files","ref":"Hibana.Plugins.Static.html#module-supported-content-types"},{"type":"function","title":"Hibana.Plugins.Static.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.Static.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.Static.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.Static.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.Upload","doc":"File upload handling plugin.","ref":"Hibana.Plugins.Upload.html"},{"type":"module","title":"Features - Hibana.Plugins.Upload","doc":"- Configurable maximum file size\n- MIME type validation\n- Custom upload directory\n- Ready-to-use upload endpoint","ref":"Hibana.Plugins.Upload.html#module-features"},{"type":"module","title":"Usage - Hibana.Plugins.Upload","doc":"plug Hibana.Plugins.Upload,\n      max_file_size: 10_000_000,\n      allowed_types: [\"image/jpeg\", \"image/png\", \"application/pdf\"],\n      upload_dir: \"priv/uploads\"","ref":"Hibana.Plugins.Upload.html#module-usage"},{"type":"module","title":"Options - Hibana.Plugins.Upload","doc":"- `:max_file_size` - Maximum file size in bytes (default: `5_000_000` = 5MB)\n- `:allowed_types` - List of allowed MIME types (default: `[]` = all)\n- `:upload_dir` - Directory to save uploads (default: `\"priv/uploads\"`)","ref":"Hibana.Plugins.Upload.html#module-options"},{"type":"module","title":"Upload Endpoint - Hibana.Plugins.Upload","doc":"POST /upload\n\nReturns JSON confirmation that endpoint is ready.\nExtend this plugin for full multipart file handling.","ref":"Hibana.Plugins.Upload.html#module-upload-endpoint"},{"type":"module","title":"Validation - Hibana.Plugins.Upload","doc":"The plugin validates:\n\n- File size against `:max_file_size`\n- MIME type against `:allowed_types` (if specified)","ref":"Hibana.Plugins.Upload.html#module-validation"},{"type":"module","title":"File Storage - Hibana.Plugins.Upload","doc":"Uploaded files are saved to `:upload_dir` with generated filenames:\n\n    priv/uploads/uuid-filename.ext","ref":"Hibana.Plugins.Upload.html#module-file-storage"},{"type":"function","title":"Hibana.Plugins.Upload.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.Upload.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.Upload.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.Upload.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.Admin","doc":"Auto-generated CRUD admin dashboard with Ant Design theme.","ref":"Hibana.Plugins.Admin.html"},{"type":"module","title":"Usage - Hibana.Plugins.Admin","doc":"plug Hibana.Plugins.Admin,\n      path: \"/admin\",\n      auth: &MyApp.admin_authorized?/1,\n      resources: [\n        {User, repo: MyApp.Repo, fields: [:name, :email, :role]},\n        {Post, repo: MyApp.Repo, fields: [:title, :body, :status]}\n      ]","ref":"Hibana.Plugins.Admin.html#module-usage"},{"type":"module","title":"Without Ecto (static data) - Hibana.Plugins.Admin","doc":"plug Hibana.Plugins.Admin,\n      path: \"/admin\",\n      resources: [\n        {:users, fields: [:name, :email, :role],\n         list_fn: &MyApp.list_users/0,\n         get_fn: &MyApp.get_user/1,\n         create_fn: &MyApp.create_user/1,\n         update_fn: &MyApp.update_user/2,\n         delete_fn: &MyApp.delete_user/1}\n      ]","ref":"Hibana.Plugins.Admin.html#module-without-ecto-static-data"},{"type":"module","title":"Features - Hibana.Plugins.Admin","doc":"- Ant Design themed responsive UI\n- Auto-generated list/show/create/edit/delete pages\n- Search and pagination\n- Works with or without Ecto\n- Customizable fields and labels\n- JSON API endpoints for AJAX operations","ref":"Hibana.Plugins.Admin.html#module-features"},{"type":"module","title":"Options - Hibana.Plugins.Admin","doc":"- `:path` - Base URL path for the admin dashboard (default: `\"/admin\"`)\n- `:resources` - List of resource tuples to manage (default: `[]`)\n- `:title` - Dashboard title displayed in the sidebar and header (default: `\"Admin Dashboard\"`)\n- `:auth` - A function `(Plug.Conn.t() -> boolean())` that checks authorization; when `nil`, the dashboard is publicly accessible (default: `nil`)","ref":"Hibana.Plugins.Admin.html#module-options"},{"type":"module","title":"Security - Hibana.Plugins.Admin","doc":"**Important:** For production use, always configure the `:auth` option with a\nfunction that checks whether the current user is authorized to access the admin\ndashboard. Without auth, the admin panel is publicly accessible.\n\n    plug Hibana.Plugins.Admin,\n      auth: fn conn -> MyApp.Auth.admin?(conn) end,\n      ...","ref":"Hibana.Plugins.Admin.html#module-security"},{"type":"function","title":"Hibana.Plugins.Admin.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.Admin.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.Admin.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.Admin.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.DevErrorPage","doc":"Rich error pages for development with stack traces, request info, and code context.","ref":"Hibana.Plugins.DevErrorPage.html"},{"type":"module","title":"Usage - Hibana.Plugins.DevErrorPage","doc":"# Only in dev!\n    plug Hibana.Plugins.DevErrorPage","ref":"Hibana.Plugins.DevErrorPage.html#module-usage"},{"type":"module","title":"Options - Hibana.Plugins.DevErrorPage","doc":"- `:enabled` - Whether the dev error page rendering is active (default: `true`)","ref":"Hibana.Plugins.DevErrorPage.html#module-options"},{"type":"function","title":"Hibana.Plugins.DevErrorPage.before_send/2","doc":"Callback implementation for  Hibana.Plugin.before_send/2 .","ref":"Hibana.Plugins.DevErrorPage.html#before_send/2"},{"type":"function","title":"Hibana.Plugins.DevErrorPage.render_exception/4","doc":"Render an exception as a rich HTML error page","ref":"Hibana.Plugins.DevErrorPage.html#render_exception/4"},{"type":"function","title":"Hibana.Plugins.DevErrorPage.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.DevErrorPage.html#start_link/1"},{"type":"module","title":"Hibana.Plugins.ErrorHandler","doc":"Custom error handler plugin for HTTP errors.","ref":"Hibana.Plugins.ErrorHandler.html"},{"type":"module","title":"Features - Hibana.Plugins.ErrorHandler","doc":"- Custom 404 (Not Found) handlers\n- Custom 500 (Server Error) handlers\n- HTML and JSON response formats\n- Pluggable error rendering functions","ref":"Hibana.Plugins.ErrorHandler.html#module-features"},{"type":"module","title":"Usage - Hibana.Plugins.ErrorHandler","doc":"# Basic usage\n    plug Hibana.Plugins.ErrorHandler\n\n    # With custom handlers\n    plug Hibana.Plugins.ErrorHandler,\n      not_found: &my_not_found_handler/1,\n      server_error: &my_error_handler/1","ref":"Hibana.Plugins.ErrorHandler.html#module-usage"},{"type":"module","title":"Options - Hibana.Plugins.ErrorHandler","doc":"- `:not_found` - Custom 4xx error handler function\n- `:server_error` - Custom 5xx error handler function","ref":"Hibana.Plugins.ErrorHandler.html#module-options"},{"type":"module","title":"Handler Functions - Hibana.Plugins.ErrorHandler","doc":"Custom handler receives the conn:\n\n    def my_not_found_handler(conn) do\n      json(conn, %{error: \"Resource not found\"})\n    end\n\n    def my_error_handler(conn) do\n      json(conn, %{error: \"Internal server error\"})\n    end","ref":"Hibana.Plugins.ErrorHandler.html#module-handler-functions"},{"type":"module","title":"Default Responses - Hibana.Plugins.ErrorHandler","doc":"**404 Not Found:**\n    HTTP 404\n       404 - Not Found   \n\n**500 Server Error:**\n    HTTP 500\n       500 - Internal Server Error","ref":"Hibana.Plugins.ErrorHandler.html#module-default-responses"},{"type":"function","title":"Hibana.Plugins.ErrorHandler.start_link/1","doc":"Callback implementation for  Hibana.Plugin.start_link/1 .","ref":"Hibana.Plugins.ErrorHandler.html#start_link/1"}],"proglang":"elixir","content_type":"text/markdown","producer":{"name":"ex_doc","version":"0.40.1"}}